-- ============================================================
-- TELECOM BILLING SCHEMA - REFERENCE DATA
-- Must be loaded AFTER 04-triggers.sql
-- Idempotent: uses ON CONFLICT DO NOTHING
-- ============================================================

-- ------------------------------------------------------------
-- RATEPLANS
-- ------------------------------------------------------------
ON CONFLICT (name) DO NOTHING;

-- ------------------------------------------------------------
-- SERVICE PACKAGES
-- ------------------------------------------------------------
ON CONFLICT DO NOTHING;

-- ------------------------------------------------------------
-- RATEPLAN SERVICE PACKAGES
-- ------------------------------------------------------------
-- Basic: gets voice + sms + data
SELECT rp.id, sp.id
FROM rateplan rp, service_package sp
WHERE rp.name = 'Basic' AND sp.name IN ('Voice Pack', 'SMS Pack', 'Data Pack')
ON CONFLICT DO NOTHING;

-- Premium Gold: gets all packages
SELECT rp.id, sp.id
FROM rateplan rp, service_package sp
WHERE rp.name = 'Premium Gold' AND sp.name IN ('Voice Pack', 'Data Pack', 'SMS Pack', 'Welcome Gift', 'Roaming Voice Pack', 'Roaming Data Pack', 'Roaming SMS Pack')
ON CONFLICT DO NOTHING;

-- Elite Enterprise: gets all packages
SELECT rp.id, sp.id
FROM rateplan rp, service_package sp
WHERE rp.name = 'Elite Enterprise' AND sp.name IN ('Voice Pack', 'Data Pack', 'SMS Pack', 'Welcome Gift', 'Roaming Voice Pack', 'Roaming Data Pack', 'Roaming SMS Pack')
ON CONFLICT DO NOTHING;

-- ------------------------------------------------------------
-- MSISDN POOL
-- ------------------------------------------------------------
ON CONFLICT (msisdn) DO NOTHING;

-- ------------------------------------------------------------
-- DEFAULT ADMIN USER (Lock-Out Prevention)
